class Solution:
  def get_projection(self, field_path: str) -> dict:
    fields = field_path.split('.')
    projection = {}
    for i in range(len(fields)):
      field = fields[i]
      if i == len(fields) - 1:
        projection[field] = 1
      else:
        projection[field] = { fields[i + 1]: 1 }
    return projection;
